UPDATE trade_cal SET is_first_of_week = CASE
WHEN exchange = #{item.exchange} AND cal_date = #{item.calDate} THEN #{item.isFirstOfWeek}
ELSE is_first_of_week END, is_last_of_week = CASE
WHEN exchange = #{item.exchange} AND cal_date = #{item.calDate} THEN #{item.isLastOfWeek}
ELSE is_last_of_week END, is_first_of_month = CASE
WHEN exchange = #{item.exchange} AND cal_date = #{item.calDate} THEN #{item.isFirstOfMonth}
ELSE is_first_of_month END, is_last_of_month = CASE
WHEN exchange = #{item.exchange} AND cal_date = #{item.calDate} THEN #{item.isLastOfMonth}
ELSE is_last_of_month END, is_first_of_quarter = CASE
WHEN exchange = #{item.exchange} AND cal_date = #{item.calDate} THEN #{item.isFirstOfQuarter}
ELSE is_first_of_quarter END, is_last_of_quarter = CASE
WHEN exchange = #{item.exchange} AND cal_date = #{item.calDate} THEN #{item.isLastOfQuarter}
ELSE is_last_of_quarter END WHERE
(exchange = #{item.exchange} AND cal_date = #{item.calDate})

